  1	import {
  2	  AccordionContent,
  3	  AccordionItem,
  4	  AccordionToggle,
  5	  Button,
  6	  Flex,
  7	  FlexItem,
  8	  Popover
  9	} from '@patternfly/react-core';
 10	import { FieldProps, UiSchema } from '@rjsf/utils';
 11	import classnames from 'classnames';
 12	import { JSONSchema7 } from 'json-schema';
 13	import * as React from 'react';
 14	import { useTranslation } from 'react-i18next';
 15	import { useTheme } from '../../../utils/theme-hook';
 16	import { useSchemaDescription, useSchemaLabel } from './utils';
 17	
 18	export const Description: React.FC<{
 19	  id?: string;
 20	  label?: string;
 21	  description?: string;
 22	  border?: boolean;
 23	  padding?: boolean;
 24	}> = ({ id, label, description, border, padding }) => {
 25	  const isDarkTheme = useTheme();
 26	  const { t } = useTranslation('plugin__netobserv-plugin');
 27	
 28	  const formatText = React.useCallback((rawText: string) => {
 29	    const tokenized = rawText.replaceAll(/(`[a-zA-Z0-9_.]+`)/g, '@@@$1@@@');
 30	    const tokens = tokenized.split('@@@');
 31	    return tokens.map(t => {
 32	      if (t === '') {
 33	        return null;
 34	      }
 35	      if (t.startsWith('`') && t.endsWith('`') && t.length > 2) {
 36	        // eslint-disable-next-line react/jsx-key
 37	        return <pre className="backticks">{t.substring(1, t.length - 1)}</pre>;
 38	      }
 39	      return t;
 40	    });
 41	  }, []);
 42	
 43	  if (!description) {
 44	    return null;
 45	  }
 46	
 47	  const desc = description.replaceAll('<br>', '');
 48	  const parts = desc.split('\n');
 49	  let content = <>{formatText(desc)}</>;
 50	  if (parts.length > 1) {
 51	    content = (
 52	      <Popover
 53	        hasAutoWidth
 54	        maxWidth="50%"
 55	        position="top"
 56	        headerContent={label}
 57	        bodyContent={<div className={`co-pre-line description`}>{content}</div>}
 58	      >
 59	        <Button
 60	          icon={
 61	            <>
 62	              {formatText(parts[0])} {t('(see more...)')}
 63	            </>
 64	          }
 65	          className={`co-pre-line description`}
 66	          variant="plain"
 67	          style={{ paddingLeft: 0 }}
 68	        />
 69	      </Popover>
 70	    );
 71	  }
 72	
 73	  return (
 74	    <span id={id} className="help-block">
 75	      <div
 76	        className={`co-pre-line description ${border ? 'border' : ''} ${padding ? 'padding' : ''} ${
 77	          isDarkTheme ? 'dark' : 'light'
 78	        }`}
 79	      >
 80	        {content}
 81	      </div>
 82	    </span>
 83	  );
 84	};
 85	
 86	export type DescriptionFieldProps = Pick<FieldProps, 'id' | 'description' | 'schema' | 'uiSchema'> & {
 87	  defaultLabel?: string;
 88	};
 89	
 90	export const DescriptionField: React.FC<DescriptionFieldProps> = ({
 91	  id,
 92	  description,
 93	  defaultLabel,
 94	  schema,
 95	  uiSchema
 96	}) => {
 97	  const [, label] = useSchemaLabel(schema, uiSchema || {}, defaultLabel);
 98	  return <Description id={id} label={label} description={description} />;
 99	};
100	
101	export type FormFieldProps = {
102	  id: string;
103	  defaultLabel?: string;
104	  required: boolean;
105	  schema: JSONSchema7;
106	  uiSchema: UiSchema;
107	};
108	
109	export const FormField: React.FC<FormFieldProps> = ({ children, id, defaultLabel, required, schema, uiSchema }) => {
110	  const { t } = useTranslation('plugin__netobserv-plugin');
111	  const [showLabel, label] = useSchemaLabel(schema, uiSchema, defaultLabel || t('Value'));
112	
113	  return (
114	    <div id={`${id}_field`} className="form-group spaced">
115	      {showLabel && label ? (
116	        <Flex direction={{ default: 'row' }}>
117	          <FlexItem flex={{ default: 'flex_1' }}>
118	            <label className={classnames('form-label', { 'co-required': required })} htmlFor={id}>
119	              {label}
120	            </label>
121	          </FlexItem>
122	          <FlexItem flex={{ default: 'flex_4' }}>{children}</FlexItem>
123	        </Flex>
124	      ) : (
125	        children
126	      )}
127	    </div>
128	  );
129	};
130	
131	export type FieldSetProps = Pick<FieldProps, 'idSchema' | 'required' | 'schema' | 'uiSchema'> & {
132	  defaultLabel?: string;
133	};
134	
135	export const FieldSet: React.FC<FieldSetProps> = props => {
136	  const { children, defaultLabel, idSchema, required = false, schema, uiSchema } = props;
137	  const [expanded, setExpanded] = React.useState(idSchema['$id'] === 'root'); // root is expanded by default
138	  const [showLabel, label] = useSchemaLabel(schema, uiSchema || {}, defaultLabel);
139	  const description = useSchemaDescription(schema, uiSchema || {});
140	  return showLabel && label ? (
141	    <div id={`${idSchema.$id}_field-group`} className="form-group co-dynamic-form__field-group">
142	      <AccordionItem>
143	        <AccordionToggle
144	          id={`${idSchema.$id}_accordion-toggle`}
145	          onClick={() => setExpanded(!expanded)}
146	
147	        >
148	          <span className={classnames({ 'co-required': required })}>{label}</span>
149	        </AccordionToggle>
150	        {description && (
151	          <Description
152	            id={`${idSchema.$id}_description`}
153	            label={label}
154	            description={description}
155	            border={expanded}
156	            padding={true}
157	          />
158	        )}
159	        <AccordionContent id={`${idSchema.$id}_accordion-content`}>
160	          {children}
161	        </AccordionContent>
162	      </AccordionItem>
163	    </div>
164	  ) : (
165	    <>{children}</>
166	  );
167	};
168	
169	// no default fields as these are imported from templates
170	export default {};

